-- calc_goals_latest_score
-- Field: Goals.LatestScore
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_goals_latest_score(p_goals_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COALESCE(MAX((score_achieved)::numeric), 0) FROM goal_updates WHERE goal = p_goals_id))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_goals_progress_pct
-- Field: Goals.ProgressPct
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_goals_progress_pct(p_goals_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (COALESCE((COALESCE(CASE WHEN ((COALESCE(CASE WHEN (calc_goals_avg_score_achieved(p_goals_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_goals_avg_score_achieved(p_goals_id))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN ((SELECT target_score FROM goals WHERE goals_id = p_goals_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT target_score FROM goals WHERE goals_id = p_goals_id))::numeric ELSE NULL END, 0), 0)))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((COALESCE(CASE WHEN (calc_goals_avg_score_achieved(p_goals_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_goals_avg_score_achieved(p_goals_id))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN ((SELECT target_score FROM goals WHERE goals_id = p_goals_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT target_score FROM goals WHERE goals_id = p_goals_id))::numeric ELSE NULL END, 0), 0)))::numeric ELSE NULL END, 0) * COALESCE(100, 0)), 0))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_goals_remaining_gap
-- Field: Goals.RemainingGap
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_goals_remaining_gap(p_goals_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (GREATEST(0, (COALESCE(CASE WHEN ((SELECT target_score FROM goals WHERE goals_id = p_goals_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT target_score FROM goals WHERE goals_id = p_goals_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN (calc_goals_avg_score_achieved(p_goals_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_goals_avg_score_achieved(p_goals_id))::numeric ELSE NULL END, 0))))::numeric;
$$ LANGUAGE sql STABLE;

